#include <iostream>\n#include <cstdint>\n#include <climits>\n#include <vector>\n\n#define INF INT64_MAX\n\nclass Graph {\n public:\n  explicit Graph(const std::vector<std::vector<int64_t>>& matrix) {\n    n_ = static_cast<int64_t>(matrix.size());\n    table_.resize(n_);\n    Build(matrix);\n  }\n\n  int64_t GetDist(int64_t a, int64_t b) {\n    a--;\n    b--;\n    std::vector<int64_t> dist(n_, INF);\n    std::vector<bool> used(n_, false);\n    dist[a] = 0;\n    for (int64_t i = 0; i < n_; i++) {\n      int64_t nearest = -1;\n      for (int64_t j = 0; j < n_; j++) {\n        if (!used[j] && (nearest == -1 || dist[j] < dist[nearest])) {\n          nearest = j;\n        }\n      }\n      if (nearest == -1) {\n        continue;\n      }\n      if (dist[nearest] == INF) {\n        break;\n      }\n      used[nearest] = true;\n      const std::vector<std::pair<int64_t, int64_t>>& children = table_[nearest];\n      for (const std::pair<int64_t, int64_t>& p : children) {\n        auto vertex = p.first;\n        auto weight = p.second;\n        dist[vertex] = std::min(dist[vertex], dist[nearest] + weight);\n      }\n    }\n    if (dist[b] == INF) {\n      return -1;\n    }\n    return dist[b];\n  }\n\n private:\n  void Build(const std::vector<std::vector<int64_t>>& matrix) {\n    for (int64_t i = 0; i < n_; i++) {\n      for (int64_t j = 0; j < n_; j++) {\n        if (i == j || matrix[i][j] == -1) {\n          continue;\n        }\n        if (i >= static_cast<int64_t>(table_.size())) {\n          table_.resize(i + 1);\n        }\n        table_[i].emplace_back(j, matrix[i][j]);\n      }\n    }\n  }\n\n  int64_t n_;\n  std::vector<std::vector<std::pair<int64_t, int64_t>>> table_;\n};\n\nint main() {\n  int64_t n = 0;\n  int64_t a = 0;\n  int64_t b = 0;\n  std::cin >> n >> a >> b;\n\n  std::vector<std::vector<int64_t>> matrix(n, std::vector<int64_t>(n));\n  for (int64_t i = 0; i < n; i++) {\n    for (int64_t j = 0; j < n; j++) {\n      std::cin >> matrix[i][j];\n    }\n  }\n\n  Graph g(matrix);\n  std::cout << g.GetDist(a, b) << std::endl;\n  return 0;\n}\n